using System;
using System.Linq;
using System.Reflection;

var asm = Assembly.LoadFrom(
    Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.UserProfile),
    ".nuget/packages/modelcontextprotocol/1.2.0/lib/net10.0/ModelContextProtocol.dll"));

var types = new[] { "McpServerToolAttribute", "McpServerToolTypeAttribute" };
foreach (var typeName in types)
{
    var type = asm.GetExportedTypes().FirstOrDefault(t => t.Name == typeName);
    if (type == null) { Console.WriteLine($"{typeName}: NOT FOUND"); continue; }
    Console.WriteLine($"\n=== {type.FullName} ===");
    foreach (var p in type.GetProperties(BindingFlags.Public | BindingFlags.Instance))
        Console.WriteLine($"  Property: {p.PropertyType.Name} {p.Name}");
    foreach (var c in type.GetConstructors())
        Console.WriteLine($"  Ctor({string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
}

// Also check if there's a Description attribute
var descAttr = asm.GetExportedTypes().FirstOrDefault(t => t.Name == "DescriptionAttribute" || t.Name == "McpServerToolDescriptionAttribute");
Console.WriteLine($"\nDescriptionAttribute in MCP: {descAttr?.FullName ?? "not found"}");

// Check extension methods for stdio
var extTypes = asm.GetExportedTypes().Where(t => t.Name.Contains("Extension") || t.Name.Contains("Builder")).ToList();
foreach (var t in extTypes)
{
    var methods = t.GetMethods(BindingFlags.Public | BindingFlags.Static)
        .Where(m => m.Name.Contains("Stdio") || m.Name.Contains("Transport"));
    foreach (var m in methods)
        Console.WriteLine($"\n{t.Name}.{m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
}
