using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerToolType]
public sealed class WeatherTools
{
    private readonly IHttpClientFactory _httpClientFactory;

    // Constructor parameters are resolved from DI automatically.
    // The SDK creates a new instance per tool invocation and injects
    // any registered services into the constructor.
    public WeatherTools(IHttpClientFactory httpClientFactory)
    {
        _httpClientFactory = httpClientFactory;
    }

    [McpServerTool(Name = "get_alerts"), Description("Get active weather alerts for a US state (e.g. CA, NY).")]
    public async Task<string> GetAlerts(string state)
    {
        using var client = _httpClientFactory.CreateClient("weather");
        using var response = await client.GetAsync($"/alerts/active/area/{state}");
        response.EnsureSuccessStatusCode();

        using var doc = await JsonDocument.ParseAsync(await response.Content.ReadAsStreamAsync());
        var features = doc.RootElement.GetProperty("features");

        if (features.GetArrayLength() == 0)
            return $"No active alerts for {state}.";

        var lines = new List<string>();
        foreach (var feature in features.EnumerateArray())
        {
            var props = feature.GetProperty("properties");
            lines.Add($"""
                Event:    {props.GetProperty("event").GetString()}
                Area:     {props.GetProperty("areaDesc").GetString()}
                Severity: {props.GetProperty("severity").GetString()}
                Headline: {props.GetProperty("headline").GetString()}
                ---
                """);
        }

        return string.Join("\n", lines);
    }

    [McpServerTool(Name = "get_forecast"), Description("Get the weather forecast for a location by latitude and longitude.")]
    public async Task<string> GetForecast(double latitude, double longitude)
    {
        using var client = _httpClientFactory.CreateClient("weather");

        // NWS API requires a point lookup first, then a forecast request.
        var pointResponse = await client.GetFromJsonAsync<JsonElement>(
            $"/points/{latitude:F4},{longitude:F4}");
        var forecastUrl = pointResponse.GetProperty("properties")
            .GetProperty("forecast").GetString()
            ?? throw new InvalidOperationException("No forecast URL returned from NWS.");

        using var forecastResponse = await client.GetAsync(forecastUrl);
        forecastResponse.EnsureSuccessStatusCode();

        using var doc = await JsonDocument.ParseAsync(await forecastResponse.Content.ReadAsStreamAsync());
        var periods = doc.RootElement.GetProperty("properties").GetProperty("periods");

        var lines = new List<string>();
        foreach (var period in periods.EnumerateArray().Take(5))
        {
            lines.Add($"""
                {period.GetProperty("name").GetString()}:
                  Temperature: {period.GetProperty("temperature").GetInt32()}°{period.GetProperty("temperatureUnit").GetString()}
                  Wind:        {period.GetProperty("windSpeed").GetString()} {period.GetProperty("windDirection").GetString()}
                  Forecast:    {period.GetProperty("detailedForecast").GetString()}
                """);
        }

        return string.Join("\n", lines);
    }
}

